import type { SensorFactory, SensorSnapshot } from 'src/agent/agent.types.ts'

type CommitEntry = {
  sha: string
  author: string
  date: string
  message: string
}

type CommitData = {
  branch: string
  commits: CommitEntry[]
}

const parseGitLog = (raw: string): CommitEntry[] =>
  raw
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => {
      const [sha, author, date, ...messageParts] = line.split('|')
      return {
        sha: sha.trim(),
        author: author.trim(),
        date: date.trim(),
        message: messageParts.join('|').trim(),
      }
    })

export const gitCommitSensor: SensorFactory = {
  name: 'git-commit',
  snapshotPath: 'git-commit.json',

  async read(signal: AbortSignal): Promise<unknown> {
    if (signal.aborted) throw new DOMException('Aborted', 'AbortError')

    // Fetch latest from remote so we see pushes from others
    await Bun.$`git fetch origin main`.quiet().catch(() => {})

    if (signal.aborted) throw new DOMException('Aborted', 'AbortError')

    const result =
      await Bun.$`git log origin/main --format=%H|%an|%aI|%s -n 20`.quiet()
    const raw = result.text()

    return {
      branch: 'main',
      commits: parseGitLog(raw),
    } satisfies CommitData
  },

  diff(current: unknown, previous: SensorSnapshot | null): unknown | null {
    const curr = current as CommitData

    // First run — report all current commits as the initial state
    if (!previous) {
      return curr.commits.length > 0 ? curr : null
    }

    const prev = previous.data as CommitData
    const knownShas = new Set(prev.commits.map((c) => c.sha))
    const newCommits = curr.commits.filter((c) => !knownShas.has(c.sha))

    if (newCommits.length === 0) return null

    return {
      branch: curr.branch,
      newCommits,
    }
  },
}

import { createGoal } from 'src/agent/agent.factories.ts'
