export const gitCommitGoal = createGoal((_trigger) => ({
  threads: {
    'git-commit-alert': bThread(
      [
        // Wait for new commits detected by the git-commit sensor
        bSync({
          waitFor: ({ type, detail }) =>
            type === AGENT_EVENTS.sensor_delta &&
            (detail as SensorDeltaDetail).sensor === 'git-commit',
        }),
        // Request a task to notify via WebSocket
        bSync({
          request: {
            type: AGENT_EVENTS.task,
            detail: {
              prompt:
                'New commits were pushed to the main branch. ' +
                'Send a WebSocket notification with the commit details ' +
                '(SHAs, authors, and messages) from the sensor delta.',
            },
          },
        }),
      ],
      true, // repeat: continuously monitor for new pushes
    ),
  },
}))

