import type { SensorFactory, SensorSnapshot } from 'src/agent/agent.types.ts'

type PdfEntry = {
  path: string
  mtimeMs: number
}

type PdfSensorData = {
  files: PdfEntry[]
}

type PdfDelta = {
  added: PdfEntry[]
}

const DOCUMENTS_DIR = `${process.env.HOME}/Documents`

export const pdfSensor: SensorFactory = {
  name: 'pdf-sensor',
  snapshotPath: 'pdfs.json',

  async read(signal: AbortSignal): Promise<unknown> {
    if (signal.aborted) throw new DOMException('Aborted', 'AbortError')

    const glob = new Bun.Glob('**/*.pdf')
    const files: PdfEntry[] = []

    for await (const relativePath of glob.scan({ cwd: DOCUMENTS_DIR, absolute: false })) {
      if (signal.aborted) throw new DOMException('Aborted', 'AbortError')

      const fullPath = `${DOCUMENTS_DIR}/${relativePath}`
      const file = Bun.file(fullPath)
      const stat = await file.stat()

      files.push({
        path: relativePath,
        mtimeMs: stat.mtimeMs,
      })
    }

    return { files } satisfies PdfSensorData
  },

  diff(current: unknown, previous: SensorSnapshot | null): unknown | null {
    const curr = current as PdfSensorData

    if (!previous) {
      return curr.files.length > 0 ? { added: curr.files } satisfies PdfDelta : null
    }

    const prev = previous.data as PdfSensorData
    const previousPaths = new Set(prev.files.map((f) => f.path))
    const added = curr.files.filter((f) => !previousPaths.has(f.path))

    return added.length > 0 ? { added } satisfies PdfDelta : null
  },
}

