import type { SensorFactory, SensorSnapshot } from 'src/agent/agent.types.ts'

type HealthStatus = {
  url: string
  statusCode: number
  ok: boolean
  timestamp: string
}

type HealthDelta = {
  url: string
  previousStatus: number | null
  currentStatus: number
  ok: boolean
  timestamp: string
}

const HEALTH_URL = 'https://api.example.com/health'

export const httpHealthSensor: SensorFactory = {
  name: 'http-health',
  snapshotPath: 'http-health.json',

  async read(signal: AbortSignal): Promise<unknown> {
    if (signal.aborted) throw new DOMException('Aborted', 'AbortError')

    try {
      const response = await fetch(HEALTH_URL, {
        signal,
        method: 'GET',
      })

      return {
        url: HEALTH_URL,
        statusCode: response.status,
        ok: response.ok,
        timestamp: new Date().toISOString(),
      } satisfies HealthStatus
    } catch (error) {
      if (signal.aborted) throw new DOMException('Aborted', 'AbortError')

      return {
        url: HEALTH_URL,
        statusCode: 0,
        ok: false,
        timestamp: new Date().toISOString(),
      } satisfies HealthStatus
    }
  },

  diff(current: unknown, previous: SensorSnapshot | null): unknown | null {
    const curr = current as HealthStatus

    if (!previous) {
      if (!curr.ok) {
        return {
          url: curr.url,
          previousStatus: null,
          currentStatus: curr.statusCode,
          ok: curr.ok,
          timestamp: curr.timestamp,
        } satisfies HealthDelta
      }
      return null
    }

    const prev = previous.data as HealthStatus

    if (curr.statusCode === prev.statusCode) return null

    return {
      url: curr.url,
      previousStatus: prev.statusCode,
      currentStatus: curr.statusCode,
      ok: curr.ok,
      timestamp: curr.timestamp,
    } satisfies HealthDelta
  },
}

import { createGoal } from 'src/agent/agent.factories.ts'
import { bThread, bSync } from 'src/behavioral/behavioral.utils.ts'
import { AGENT_EVENTS } from 'src/agent/agent.constants.ts'
import type { SensorDeltaDetail } from 'src/agent/agent.types.ts'
import type { DefaultHandlers } from 'src/behavioral/behavioral.types.ts'

type HealthDelta = {
  url: string
  previousStatus: number | null
  currentStatus: number
  ok: boolean
  timestamp: string
}

const isNon200HealthDelta = ({ type, detail }: { type: string; detail: unknown }): boolean => {
  if (type !== AGENT_EVENTS.sensor_delta) return false
  const sensorDetail = detail as SensorDeltaDetail
  if (sensorDetail.sensor !== 'http-health') return false
  const delta = sensorDetail.delta as HealthDelta
  return !delta.ok
}

const formatAlertMessage = (delta: HealthDelta): string => {
  const statusChange = delta.previousStatus !== null
    ? `Status changed from ${delta.previousStatus} to ${delta.currentStatus}`
    : `Initial check returned status ${delta.currentStatus}`

  return [
    `**Health Check Alert**`,
    `URL: ${delta.url}`,
    statusChange,
    `Time: ${delta.timestamp}`,
  ].join('\n')
}

const discordNotificationHandler: DefaultHandlers = {
  [AGENT_EVENTS.message]: ({ detail }) => {
    const msg = detail as { source?: string; content?: string }
    if (msg.source !== 'proactive') return

    const webhookUrl = process.env.DISCORD_WEBHOOK_URL
    if (!webhookUrl) return

    fetch(webhookUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ content: msg.content }),
    }).catch(() => {/* non-fatal */})
  },
}

export const httpHealthGoal = createGoal((_trigger) => ({
  threads: {
    'http-health-alert': bThread(
      [
        bSync({
          waitFor: isNon200HealthDelta,
        }),
        bSync({
          request: {
            type: AGENT_EVENTS.task,
            detail: {
              prompt:
                'The HTTP health check sensor detected a non-200 status code from https://api.example.com/health. ' +
                'Send an alert via the proactive message channel with details about the status change.',
            },
          },
        }),
      ],
      true,
    ),
  },
  handlers: discordNotificationHandler,
}))

