import { createGoal } from 'src/agent/agent.factories.ts'
import { bThread, bSync } from 'src/behavioral/behavioral.utils.ts'
import { AGENT_EVENTS } from 'src/agent/agent.constants.ts'
import type { SensorDeltaDetail } from 'src/agent/agent.types.ts'
import type { DefaultHandlers } from 'src/behavioral/behavioral.types.ts'

type AccumulatedDelta = {
  sensor: string
  delta: unknown
  timestamp: string
}

const TWENTY_FOUR_HOURS_MS = 24 * 60 * 60 * 1000

const pruneOlderThan24h = (deltas: AccumulatedDelta[]): AccumulatedDelta[] => {
  const cutoff = Date.now() - TWENTY_FOUR_HOURS_MS
  return deltas.filter((d) => new Date(d.timestamp).getTime() >= cutoff)
}

const formatDigestHtml = (deltas: AccumulatedDelta[]): string => {
  if (deltas.length === 0) {
    return `
      <h2>Daily Sensor Digest</h2>
      <p>No sensor changes detected in the past 24 hours.</p>
    `
  }

  const rows = deltas
    .map(
      (d) =>
        `<tr>
          <td style="white-space:nowrap">${d.timestamp}</td>
          <td>${d.sensor}</td>
          <td><pre style="margin:0">${JSON.stringify(d.delta, null, 2)}</pre></td>
        </tr>`,
    )
    .join('\n')

  return `
    <h2>Daily Sensor Digest</h2>
    <p>${deltas.length} change(s) detected in the past 24 hours.</p>
    <table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse">
      <thead>
        <tr><th>Timestamp</th><th>Sensor</th><th>Delta</th></tr>
      </thead>
      <tbody>
        ${rows}
      </tbody>
    </table>
  `
}

export const emailDigestGoal = createGoal((_trigger) => {
  const collected: AccumulatedDelta[] = []

  const handlers: DefaultHandlers = {
    [AGENT_EVENTS.sensor_delta]: ({ detail }) => {
      const d = detail as SensorDeltaDetail
      collected.push({
        sensor: d.sensor,
        delta: d.delta,
        timestamp: new Date().toISOString(),
      })
    },

    [AGENT_EVENTS.message]: ({ detail }) => {
      const msg = detail as { source?: string; content?: string }
      if (msg.source !== 'proactive') return

      const smtpRelayUrl = process.env.SMTP_RELAY_URL
      const emailTo = process.env.DIGEST_EMAIL_TO
      if (!smtpRelayUrl || !emailTo) return

      const emailFrom = process.env.DIGEST_EMAIL_FROM ?? 'agent@example.com'
      const dateStr = new Date().toLocaleDateString('en-US', {
        weekday: 'long',
        year: 'numeric',
        month: 'long',
        day: 'numeric',
      })

      const recent = pruneOlderThan24h(collected)
      const html = formatDigestHtml(recent)

      fetch(smtpRelayUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          from: emailFrom,
          to: emailTo,
          subject: `Daily Sensor Digest — ${dateStr}`,
          html,
        }),
      }).catch(() => {
        /* non-fatal */
      })

      collected.length = 0
    },
  }

  return {
    threads: {
      'email-digest': bThread(
        [
          // Step 1: Wait for at least one sensor delta to arrive
          bSync({
            waitFor: ({ type }) => type === AGENT_EVENTS.sensor_delta,
          }),
          // Step 2: Wait for the 8am tick to fire the digest
          bSync({
            waitFor: ({ type }) =>
              type === AGENT_EVENTS.tick && new Date().getHours() === 8,
          }),
          // Step 3: Request the agent to compose and send the digest
          bSync({
            request: {
              type: AGENT_EVENTS.task,
              detail: {
                prompt:
                  'Compose and send a daily digest email summarizing all sensor changes detected in the past 24 hours. Group changes by sensor name, include timestamps, and format the result as an HTML email.',
              },
            },
          }),
        ],
        true, // repeat: restart the cycle after each digest is sent
      ),
    },
    handlers,
  }
})

import type { SensorFactory, SensorSnapshot } from 'src/agent/agent.types.ts'

type BackendStatus = {
  backend: 'local' | 'cloud'
  localEndpoint: string
  timestamp: number
}

type BackendDelta = {
  backend: 'local' | 'cloud'
  previousBackend: 'local' | 'cloud' | null
}

const LOCAL_ENDPOINT = process.env.LOCAL_INFERENCE_URL ?? 'http://localhost:11434'

export const inferenceBackendSensor: SensorFactory = {
  name: 'inference-backend',
  snapshotPath: 'inference-backend.json',

  async read(signal: AbortSignal): Promise<unknown> {
    const endpoint = `${LOCAL_ENDPOINT}/api/tags`
    try {
      const res = await fetch(endpoint, { signal })
      return {
        backend: res.ok ? 'local' : 'cloud',
        localEndpoint: LOCAL_ENDPOINT,
        timestamp: Date.now(),
      } satisfies BackendStatus
    } catch {
      return {
        backend: 'cloud',
        localEndpoint: LOCAL_ENDPOINT,
        timestamp: Date.now(),
      } satisfies BackendStatus
    }
  },

  diff(current: unknown, previous: SensorSnapshot | null): unknown | null {
    const curr = current as BackendStatus
    if (!previous) {
      return { backend: curr.backend, previousBackend: null } satisfies BackendDelta
    }
    const prev = previous.data as BackendStatus
    if (curr.backend === prev.backend) return null
    return { backend: curr.backend, previousBackend: prev.backend } satisfies BackendDelta
  },
}

import { createGoal } from 'src/agent/agent.factories.ts'
import { bThread, bSync } from 'src/behavioral/behavioral.utils.ts'
import { AGENT_EVENTS } from 'src/agent/agent.constants.ts'
import type { SensorDeltaDetail } from 'src/agent/agent.types.ts'

const AGGRESSIVE_INTERVAL_MS = 300_000     // 5 minutes — local GPU
const CONSERVATIVE_INTERVAL_MS = 7_200_000 // 2 hours  — cloud API

type BackendDelta = {
  backend: 'local' | 'cloud'
  previousBackend: 'local' | 'cloud' | null
}

const isBackendDelta = (type: string, detail: unknown, target: 'local' | 'cloud'): boolean => {
  if (type !== AGENT_EVENTS.sensor_delta) return false
  const d = detail as SensorDeltaDetail
  if (d.sensor !== 'inference-backend') return false
  const delta = d.delta as BackendDelta
  return delta.backend === target
}

export const costAwareHeartbeatGoal = createGoal((_trigger) => ({
  threads: {
    // When backend falls back to cloud API, slow the heartbeat to save money
    'switch-to-conservative': bThread(
      [
        bSync({
          waitFor: ({ type, detail }) => isBackendDelta(type, detail, 'cloud'),
        }),
        bSync({
          request: {
            type: AGENT_EVENTS.set_heartbeat,
            detail: { intervalMs: CONSERVATIVE_INTERVAL_MS },
          },
        }),
        bSync({
          request: {
            type: AGENT_EVENTS.task,
            detail: {
              prompt:
                'Inference backend switched to cloud API. Heartbeat adjusted to 2-hour interval to reduce costs. Log the transition and summarize current sensor states.',
            },
          },
        }),
      ],
      true,
    ),

    // When local GPU comes back online, ramp up to aggressive monitoring
    'switch-to-aggressive': bThread(
      [
        bSync({
          waitFor: ({ type, detail }) => isBackendDelta(type, detail, 'local'),
        }),
        bSync({
          request: {
            type: AGENT_EVENTS.set_heartbeat,
            detail: { intervalMs: AGGRESSIVE_INTERVAL_MS },
          },
        }),
        bSync({
          request: {
            type: AGENT_EVENTS.task,
            detail: {
              prompt:
                'Inference backend switched to local GPU. Heartbeat adjusted to 5-minute interval for aggressive monitoring. Log the transition and summarize current sensor states.',
            },
          },
        }),
      ],
      true,
    ),
  },
}))

import { createAgentLoop } from 'src/agent/agent.loop.ts'
import { inferenceBackendSensor } from './inference-backend-sensor.ts'
import { costAwareHeartbeatGoal } from './cost-aware-heartbeat-goal.ts'

const INITIAL_INTERVAL_MS = 300_000 // start aggressive; goal adjusts if cloud

export const agentLoop = createAgentLoop({
  proactive: {
    sensors: [inferenceBackendSensor],
    goals: [costAwareHeartbeatGoal],
    intervalMs: INITIAL_INTERVAL_MS,
  },
})
